# 示例3：左右指针——寻找数组中两数之和（已排序数组）
def two_sum_sorted(nums, target):
    left, right = 0, len(nums) - 1

    while left < right:
        current = nums[left] + nums[right]
        if current == target:
            return [left, right]
        elif current < target:
            left += 1   # 和太小，左指针右移增大
        else:
            right -= 1  # 和太大，右指针左移减小

    return None

print(two_sum_sorted([1, 2, 4, 6, 8, 11], 10))  # 输出: [1, 4] 即 2+8=10
